-- в”Ђв”Ђ LinkWhisper в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$WordPress plugin that uses AI to suggest, automate, and audit internal links to improve on-site SEO.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$97/year$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small, boutique SaaS team$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$LinkWhisper Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LinkWhisper review 2026: AI-powered internal linking plugin for WordPress SEO. Compare features, pricing tiers, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LinkWhisper is a WordPress plugin built specifically to automate and improve internal linking, a well-known but tedious SEO task that involves connecting related pages and posts on a website to strengthen topical authority, distribute link equity, and help search engines crawl and understand site structure. The plugin was created by Spencer Haws, the founder of the popular SEO and online business blog Niche Pursuits, who has built and sold multiple online businesses since starting full-time online work in 2011. LinkWhisper launched around 2019 in response to a recurring pain point Haws observed among content publishers and SEO practitioners: internal linking is one of the highest-leverage, lowest-cost SEO tactics, but manually finding and inserting relevant internal links across hundreds or thousands of posts is impractical at scale. Architecturally, LinkWhisper is a WordPress plugin (with a companion Shopify app for e-commerce sites) that scans a site's existing content and, using natural-language and semantic-relevance analysis, suggests contextually appropriate internal links as an author writes or edits a post. Its AI is designed to read content the way a human SEO editor would, identifying topic relationships and relevant anchor text rather than relying purely on keyword matching. Core capabilities include one-click AI-powered link insertion, automatic link suggestions during content creation, a broken-link detector that finds and helps fix dead internal links, an orphaned-page finder that surfaces pages with no internal links pointing to them (a common and often invisible SEO problem), and an auto-linking feature that can retroactively add internal links across existing content in bulk, saving what would otherwise be hours of manual work per site. A free version of the plugin is available in the official WordPress.org plugin directory and provides a limited but functional version of the internal-linking suggestion engine, useful for evaluating the core concept before upgrading. The paid version is where most of the automation value lives, particularly one-click bulk insertion and full auto-linking across a site's content library, which the vendor and independent reviewers both position as the primary reason publishers upgrade from free to premium. LinkWhisper is sold exclusively on annual billing, with four tiers scaling by the number of WordPress sites covered: Starter at $97 per year for one site, Growth at $197 per year for three sites, Pro at $297 per year for ten sites, and Agency at $497 per year for fifty sites, with the Agency tier also including a bundle of AI credits (reported around 10,000). All paid tiers include the same core feature set, AI-powered suggestions, broken-link detection, orphan-page finding, and auto-linking, with the differentiator being site count rather than functionality, and additional AI credits can be purchased separately as an add-on for very high-volume usage. LinkWhisper offers a 7-day free trial of the premium version and backs purchases with a 60-day money-back guarantee, a relatively generous window for a WordPress plugin category. The target audience is primarily WordPress-based content publishers, SEO agencies managing multiple client sites, affiliate marketers, and bloggers who publish at volume and need to keep internal linking current as their content libraries grow, since manually auditing internal links on large sites becomes unmanageable without tooling. LinkWhisper competes with broader all-in-one SEO plugins that include some internal-linking features (such as Rank Math and Yoast SEO) as well as dedicated content-optimization tools like Link Whisper's closest direct rival, and it differentiates itself by focusing narrowly and deeply on internal linking rather than being a general SEO suite, offering more sophisticated AI-driven suggestion and bulk-automation capabilities than the internal-linking modules bundled into general-purpose SEO plugins.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9f9df18c-f8de-4006-956e-f16fecbef694';

